// Curated Danish recipe library — handwritten, no auto-generated variants.
// Every recipe is unique with realistic ingredients & macros.

export type RecipeCategory = "breakfast" | "lunch" | "dinner" | "snack" | "smoothie" | "dessert" | "drink" | "worldcuisine";
export type RecipeTag = "high-protein" | "low-carb" | "vegetarian" | "quick" | "low-cal" | "mealprep" | "asian" | "dessert" | "smoothie" | "drink" | "pasta" | "chicken" | "beef" | "fish" | "vegan" | "worldcuisine";

export type Recipe = {
  id: string;
  name: string;
  emoji: string;
  category: RecipeCategory;
  tags: RecipeTag[];
  minutes: number;
  servings: number;
  calories: number;
  protein: number;
  carbs: number;
  fat: number;
  ingredients: string[];
  steps: string[];
  /** Oven/pan temperature in °C, when relevant. */
  tempC?: number;
  /** Country/cuisine label for World Cuisine recipes. */
  cuisine?: string;
};

const r = (
  id: string, name: string, emoji: string, category: RecipeCategory, tags: RecipeTag[],
  minutes: number, cal: number, p: number, c: number, f: number,
  ingredients: string[], steps: string[], tempC?: number,
): Recipe => ({
  id, name, emoji, category, tags, minutes, servings: 1,
  calories: cal, protein: p, carbs: c, fat: f, ingredients, steps, tempC,
});

// World Cuisine helper — adds country label
const w = (
  id: string, country: string, name: string, emoji: string,
  minutes: number, cal: number, p: number, c: number, f: number,
  ingredients: string[], steps: string[], tempC?: number,
): Recipe => ({
  id, name, emoji, category: "worldcuisine",
  tags: ["worldcuisine"], minutes, servings: 2,
  calories: cal, protein: p, carbs: c, fat: f, ingredients, steps, tempC,
  cuisine: country,
});

